import asyncio
import websockets

class GameServer:
    def __init__(self):
        self.players = {}
        self.items = {}

    async def trade_items(self, sender, receiver, item_id):
        if item_id in self.players[sender]['inventory']:
            self.players[sender]['inventory'].remove(item_id)
            self.players[receiver]['inventory'].append(item_id)

    async def update_item_ownership(self, player_id, item_id):
        if item_id in self.items:
            self.items[item_id] = player_id

    async def handle_client(self, websocket, path):
        player_id = await websocket.recv()
        self.players[player_id] = {'inventory': []}

        try:
            async for message in websocket:
                data = message.split(',')
                if data[0] == 'trade':
                    await self.trade_items(player_id, data[1], int(data[2]))
                elif data[0] == 'update':
                    await self.update_item_ownership(player_id, int(data[1]))
        finally:
            del self.players[player_id]

server = GameServer()
start_server = websockets.serve(server.handle_client, 'localhost', 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()